    83	fn is_right_child(parent: &Rc<RefCell<BOSNode>>, child: &Rc<RefCell<BOSNode>>) -> bool {
    84	    parent
    85	        .borrow()
    86	        .right_child_node
    87	        .as_ref()
    88	        .map_or(false, |right| Rc::ptr_eq(right, child))
