    96	impl BOSTree {
    97	    /// Create a new tree with a mandatory comparison function and an optional free function.
    98	    pub fn bostree_new(
    99	        cmp_function: BOSTreeCmpFunction,
   100	        free_function: Option<BOSTreeFreeFunction>,
   101	    ) -> Self {
   102	        Self {
   103	            root_node: None,
   104	            cmp_function,
   105	            free_function,
   106	        }
   107	    }
   108	    /// Return the number of nodes in the tree.
   109	    pub fn bostree_node_count(&self) -> u32 {
   110	        self.root_node.as_ref().map_or(0, node_total_count)
   111	    }
   112	
   113	    fn rotate_right(&mut self, pivot: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
   114	        let left = pivot
   115	            .borrow()
   116	            .left_child_node
   117	            .clone()
   118	            .expect("right rotation requires a left child");
   119	        let old_parent = parent_node(pivot);
   120	        let left_right = left.borrow().right_child_node.clone();
   120	        let left_right = left.borrow().right_child_node.clone();
   121	        let left_right_count = left.borrow().right_child_count;
   122	
   123	        if let Some(parent) = old_parent.as_ref() {
   124	            if is_left_child(parent, pivot) {
   125	                parent.borrow_mut().left_child_node = Some(left.clone());
   126	            } else {
   127	                parent.borrow_mut().right_child_node = Some(left.clone());
   128	            }
   129	        } else {
   130	            self.root_node = Some(left.clone());
   131	        }
   132	        left.borrow_mut().parent_node = old_parent.as_ref().map(downgrade_node);
   133	
   134	        {
   135	            let mut pivot_mut = pivot.borrow_mut();
   136	            pivot_mut.left_child_node = left_right.clone();
   137	            pivot_mut.left_child_count = left_right_count;
   138	        }
   139	        if let Some(child) = left_right {
   140	            child.borrow_mut().parent_node = Some(downgrade_node(pivot));
   141	        }
   142	        update_depth(pivot);
   143	
   144	        let pivot_count = node_total_count(pivot);
   145	        {
   146	            let mut left_mut = left.borrow_mut();
   147	            left_mut.right_child_node = Some(pivot.clone());
   148	            left_mut.right_child_count = pivot_count;
   149	        }
   150	        pivot.borrow_mut().parent_node = Some(downgrade_node(&left));
   151	        update_depth(&left);
   152	
   153	        left
   154	    }
   155	
   156	    fn rotate_left(&mut self, pivot: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
   157	        let right = pivot
   158	            .borrow()
   159	            .right_child_node
   160	            .clone()
   161	            .expect("left rotation requires a right child");
   162	        let old_parent = parent_node(pivot);
   163	        let right_left = right.borrow().left_child_node.clone();
   164	        let right_left_count = right.borrow().left_child_count;
   165	
   166	        if let Some(parent) = old_parent.as_ref() {
   167	            if is_left_child(parent, pivot) {
   168	                parent.borrow_mut().left_child_node = Some(right.clone());
   169	            } else {
   170	                parent.borrow_mut().right_child_node = Some(right.clone());
   171	            }
   172	        } else {
   173	            self.root_node = Some(right.clone());
   174	        }
   175	        right.borrow_mut().parent_node = old_parent.as_ref().map(downgrade_node);
   176	
   177	        {
   178	            let mut pivot_mut = pivot.borrow_mut();
   179	            pivot_mut.right_child_node = right_left.clone();
   180	            pivot_mut.right_child_count = right_left_count;
   181	        }
   182	        if let Some(child) = right_left {
   183	            child.borrow_mut().parent_node = Some(downgrade_node(pivot));
   184	        }
   185	        update_depth(pivot);
   186	
   187	        let pivot_count = node_total_count(pivot);
   188	        {
   189	            let mut right_mut = right.borrow_mut();
   190	            right_mut.left_child_node = Some(pivot.clone());
   191	            right_mut.left_child_count = pivot_count;
   192	        }
   193	        pivot.borrow_mut().parent_node = Some(downgrade_node(&right));
   194	        update_depth(&right);
   195	
   196	        right
   197	    }
   198	
   199	    fn rebalance_after_insert(&mut self, mut node: Option<Rc<RefCell<BOSNode>>>) {
   200	        while let Some(current) = node {
   201	            update_depth(&current);
   202	            let current_balance = balance(&current);
   203	
   204	            let rebalanced = if current_balance < -1 {
   205	                let left = current.borrow().left_child_node.clone().unwrap();
   206	                if balance(&left) > 0 {
   207	                    self.rotate_left(&left);
   208	                }
   209	                self.rotate_right(&current)
   210	            } else if current_balance > 1 {
   211	                let right = current.borrow().right_child_node.clone().unwrap();
   212	                if balance(&right) < 0 {
   213	                    self.rotate_right(&right);
   214	                }
   215	                self.rotate_left(&current)
   216	            } else {
   217	                current.clone()
   218	            };
   219	
   220	            node = parent_node(&rebalanced);
   221	        }
   222	    }
