   224	    /// Insert a new member into the tree and return the associated node.
   225	    pub fn bostree_insert(&mut self, key: String, data: Option<String>) -> Rc<RefCell<BOSNode>> {
   226	        let new_node = Rc::new(RefCell::new(BOSNode {
   227	            left_child_count: 0,
   228	            right_child_count: 0,
   229	            depth: 0,
   230	            left_child_node: None,
   231	            right_child_node: None,
   232	            parent_node: None,
   233	            key,
   234	            data,
   235	            weak_ref_count: 1,
   236	            weak_ref_node_valid: 1,
   237	        }));
   238	
   239	        let Some(mut current) = self.root_node.clone() else {
   240	            self.root_node = Some(new_node.clone());
   241	            return new_node;
   242	        };
   243	
   244	        loop {
   245	            let cmp = {
   246	                let current_borrow = current.borrow();
   247	                (self.cmp_function)(&new_node.borrow().key, &current_borrow.key)
   248	            };
   249	
   250	            if cmp < 0 {
   251	                let next = {
   252	                    let mut current_mut = current.borrow_mut();
   253	                    current_mut.left_child_count += 1;
   254	                    current_mut.left_child_node.clone()
   255	                };
   256	                if let Some(next_node) = next {
   257	                    current = next_node;
   258	                } else {
   259	                    new_node.borrow_mut().parent_node = Some(downgrade_node(&current));
   260	                    current.borrow_mut().left_child_node = Some(new_node.clone());
   260	                    current.borrow_mut().left_child_node = Some(new_node.clone());
   261	                    self.rebalance_after_insert(Some(current));
   262	                    return new_node;
   263	                }
   264	            } else {
   265	                let next = {
   266	                    let mut current_mut = current.borrow_mut();
   267	                    current_mut.right_child_count += 1;
   268	                    current_mut.right_child_node.clone()
   269	                };
   270	                if let Some(next_node) = next {
   271	                    current = next_node;
   272	                } else {
   273	                    new_node.borrow_mut().parent_node = Some(downgrade_node(&current));
   274	                    current.borrow_mut().right_child_node = Some(new_node.clone());
   275	                    self.rebalance_after_insert(Some(current));
   276	                    return new_node;
   277	                }
   278	            }
   279	        }
   280	    }
   281	    /// Remove a given node from the tree.
   282	    pub fn bostree_remove(&mut self, node: &Rc<RefCell<BOSNode>>) {
   283	        if node.borrow().weak_ref_node_valid == 0 {
   284	            return;
   285	        }
   286	
   287	        let mut bubble_up = None;
   288	        let has_left = node.borrow().left_child_node.is_some();
   289	        let has_right = node.borrow().right_child_node.is_some();
   290	
   291	        if has_left && has_right {
   292	            let left_depth = node
   293	                .borrow()
   294	                .left_child_node
   295	                .as_ref()
   296	                .map_or(0, |left| left.borrow().depth);
   297	            let right_depth = node
   298	                .borrow()
   299	                .right_child_node
   300	                .as_ref()
   301	                .map_or(0, |right| right.borrow().depth);
   302	
   303	            let (candidate, lost_child) = if left_depth >= right_depth {
   304	                node.borrow_mut().left_child_count -= 1;
   305	                let mut candidate = node.borrow().left_child_node.clone().unwrap();
   306	                loop {
   307	                    let next = candidate.borrow().right_child_node.clone();
   308	                    if let Some(next_candidate) = next {
   309	                        candidate.borrow_mut().right_child_count -= 1;
   310	                        candidate = next_candidate;
   311	                    } else {
   312	                        break;
   313	                    }
   314	                }
   315	                let lost_child = candidate.borrow().left_child_node.clone();
   316	                (candidate, lost_child)
   317	            } else {
   318	                node.borrow_mut().right_child_count -= 1;
   319	                let mut candidate = node.borrow().right_child_node.clone().unwrap();
   320	                loop {
   321	                    let next = candidate.borrow().left_child_node.clone();
   322	                    if let Some(next_candidate) = next {
   323	                        candidate.borrow_mut().left_child_count -= 1;
   324	                        candidate = next_candidate;
   325	                    } else {
   326	                        break;
   327	                    }
   328	                }
   329	                let lost_child = candidate.borrow().right_child_node.clone();
   330	                (candidate, lost_child)
   331	            };
   332	
   333	            let mut bubble_start = parent_node(&candidate).unwrap();
   334	            if is_left_child(&bubble_start, &candidate) {
   335	                bubble_start.borrow_mut().left_child_node = lost_child.clone();
   336	            } else {
   337	                bubble_start.borrow_mut().right_child_node = lost_child.clone();
   338	            }
   339	            if let Some(child) = lost_child.as_ref() {
   340	                child.borrow_mut().parent_node = Some(downgrade_node(&bubble_start));
   341	            }
   342	
   343	            let old_parent = parent_node(node);
   344	            if let Some(parent) = old_parent.as_ref() {
   345	                if is_left_child(parent, node) {
   346	                    parent.borrow_mut().left_child_node = Some(candidate.clone());
   347	                } else {
   348	                    parent.borrow_mut().right_child_node = Some(candidate.clone());
   349	                }
   350	            } else {
   351	                self.root_node = Some(candidate.clone());
   352	            }
   353	            candidate.borrow_mut().parent_node = old_parent.as_ref().map(downgrade_node);
   354	
   355	            let (left_child, left_count, right_child, right_count) = {
   356	                let borrowed = node.borrow();
   357	                (
   358	                    borrowed.left_child_node.clone(),
   359	                    borrowed.left_child_count,
   360	                    borrowed.right_child_node.clone(),
   361	                    borrowed.right_child_count,
   362	                )
   363	            };
   364	            {
   365	                let mut candidate_mut = candidate.borrow_mut();
   366	                candidate_mut.left_child_node = left_child.clone();
   367	                candidate_mut.left_child_count = left_count;
   368	                candidate_mut.right_child_node = right_child.clone();
   369	                candidate_mut.right_child_count = right_count;
   370	            }
   371	            if let Some(child) = left_child.as_ref() {
   372	                child.borrow_mut().parent_node = Some(downgrade_node(&candidate));
   373	            }
   374	            if let Some(child) = right_child.as_ref() {
   375	                child.borrow_mut().parent_node = Some(downgrade_node(&candidate));
   376	            }
   377	
   378	            if !Rc::ptr_eq(&bubble_start, node) {
   379	                while !Rc::ptr_eq(&bubble_start, &candidate) {
   380	                    update_depth(&bubble_start);
   381	                    let current_balance = balance(&bubble_start);
   382	                    if current_balance > 1 {
   383	                        let right = bubble_start.borrow().right_child_node.clone().unwrap();
   384	                        if balance(&right) < 0 {
   385	                            self.rotate_right(&right);
   386	                        }
   387	                        bubble_start = self.rotate_left(&bubble_start);
   388	                    } else if current_balance < -1 {
   389	                        let left = bubble_start.borrow().left_child_node.clone().unwrap();
   390	                        if balance(&left) > 0 {
   391	                            self.rotate_left(&left);
   392	                        }
   393	                        bubble_start = self.rotate_right(&bubble_start);
   394	                    }
   395	
   396	                    let Some(parent) = parent_node(&bubble_start) else {
   397	                        break;
   398	                    };
   399	                    bubble_start = parent;
   400	                }
   401	            }
   402	
   403	            update_depth(&candidate);
   404	            bubble_up = parent_node(&candidate);
   405	            if let Some(parent) = bubble_up.as_ref() {
   406	                if is_left_child(parent, &candidate) {
   407	                    parent.borrow_mut().left_child_count -= 1;
   408	                } else {
   409	                    parent.borrow_mut().right_child_count -= 1;
   410	                }
   411	            }
   412	        } else {
   413	            let (replacement, replacement_count) = {
   414	                let borrowed = node.borrow();
   415	                if borrowed.left_child_node.is_some() {
   416	                    (borrowed.left_child_node.clone(), borrowed.left_child_count)
   417	                } else {
   418	                    (borrowed.right_child_node.clone(), borrowed.right_child_count)
   419	                }
   420	            };
   421	
   422	            if let Some(parent) = parent_node(node) {
   423	                if is_left_child(&parent, node) {
   424	                    let mut parent_mut = parent.borrow_mut();
   425	                    parent_mut.left_child_node = replacement.clone();
   426	                    parent_mut.left_child_count = replacement_count;
   427	                } else {
   428	                    let mut parent_mut = parent.borrow_mut();
   429	                    parent_mut.right_child_node = replacement.clone();
   430	                    parent_mut.right_child_count = replacement_count;
   431	                }
   432	                if let Some(child) = replacement.as_ref() {
   433	                    child.borrow_mut().parent_node = Some(downgrade_node(&parent));
   434	                }
   435	                bubble_up = Some(parent);
   436	            } else {
   437	                self.root_node = replacement.clone();
   438	                if let Some(child) = replacement.as_ref() {
   439	                    child.borrow_mut().parent_node = None;
   440	                }
   441	            }
   442	        }
   443	
   444	        let mut bubbling_finished = false;
   445	        while let Some(current) = bubble_up {
   446	            let mut rebalanced = current.clone();
   447	            if !bubbling_finished {
   448	                let old_depth = current.borrow().depth;
   449	                let new_depth = update_depth(&current);
   450	                let depth_changed = new_depth != old_depth;
   451	                let current_balance = balance(&current);
   452	
   453	                if current_balance < -1 {
   454	                    let left = current.borrow().left_child_node.clone().unwrap();
   455	                    if balance(&left) > 0 {
   456	                        self.rotate_left(&left);
   457	                    }
   458	                    rebalanced = self.rotate_right(&current);
   459	                } else if current_balance > 1 {
   460	                    let right = current.borrow().right_child_node.clone().unwrap();
   461	                    if balance(&right) < 0 {
   462	                        self.rotate_right(&right);
   463	                    }
   464	                    rebalanced = self.rotate_left(&current);
   465	                } else if !depth_changed {
   466	                    bubbling_finished = true;
   467	                }
   468	            }
   469	
   470	            if let Some(parent) = parent_node(&rebalanced) {
   471	                if is_left_child(&parent, &rebalanced) {
   472	                    parent.borrow_mut().left_child_count -= 1;
   473	                } else {
   474	                    parent.borrow_mut().right_child_count -= 1;
   475	                }
   476	                bubble_up = Some(parent);
   477	            } else {
   478	                bubble_up = None;
   479	            }
   480	        }
   481	
   482	        {
   483	            let mut node_mut = node.borrow_mut();
   484	            node_mut.weak_ref_node_valid = 0;
   485	            node_mut.parent_node = None;
   486	            node_mut.left_child_node = None;
   487	            node_mut.right_child_node = None;
   488	            node_mut.left_child_count = 0;
   489	            node_mut.right_child_count = 0;
   490	            node_mut.depth = 0;
   491	        }
   492	        let _ = self.bostree_node_weak_unref(node);
   493	    }
   494	    /// Decrease the weak reference count for a node; if that was the last reference,
   495	    /// free the node and return None; otherwise return the node.
   496	    pub fn bostree_node_weak_unref(
   497	        &mut self,
   498	        node: &Rc<RefCell<BOSNode>>,
   499	    ) -> Option<Rc<RefCell<BOSNode>>> {
   500	        {
   501	            let mut node_mut = node.borrow_mut();
   502	            assert!(node_mut.weak_ref_count > 0);
   503	            node_mut.weak_ref_count -= 1;
   504	        }
   505	
   506	        if node.borrow().weak_ref_count == 0 {
   507	            if let Some(free_function) = self.free_function {
   508	                free_function(node);
   509	            }
   510	            None
   511	        } else if node.borrow().weak_ref_node_valid != 0 {
   512	            Some(node.clone())
   513	        } else {
   514	            None
   515	        }
   516	    }
   517	    /// Lookup a node in the tree by its key.
   518	    pub fn bostree_lookup(&self, key: &str) -> Option<Rc<RefCell<BOSNode>>> {
   519	        let mut node = self.root_node.clone();
   520	        while let Some(current) = node {
   520	        while let Some(current) = node {
   521	            let cmp = (self.cmp_function)(key, &current.borrow().key);
   522	            if cmp == 0 {
   523	                return Some(current);
   524	            }
   525	            node = if cmp < 0 {
   526	                current.borrow().left_child_node.clone()
   527	            } else {
   528	                current.borrow().right_child_node.clone()
   529	            };
   530	        }
   531	        None
   532	    }
   533	    /// Return the node at the given in-order index (starting at 0).
   534	    pub fn bostree_select(&self, index: u32) -> Option<Rc<RefCell<BOSNode>>> {
   535	        let mut index = index;
   536	        let mut node = self.root_node.clone();
   537	        while let Some(current) = node {
   538	            let left_count = current.borrow().left_child_count;
   539	            if left_count <= index {
   540	                index -= left_count;
   541	                if index == 0 {
   542	                    return Some(current);
   543	                }
   544	                index -= 1;
   545	                node = current.borrow().right_child_node.clone();
   546	            } else {
   547	                node = current.borrow().left_child_node.clone();
   548	            }
   549	        }
   550	        None
   551	    }
   552	    /// Print the tree (only available in debug builds).
   553	    #[cfg(debug_assertions)]
   554	    pub fn bostree_print(&self) {
   555	        fn print_node(node: &Rc<RefCell<BOSNode>>) {
   556	            let borrowed = node.borrow();
   557	            println!(
   558	                "  {} [label=\"\\N ({},{},{})\"];",
   559	                borrowed.key, borrowed.left_child_count, borrowed.right_child_count, borrowed.depth
   560	            );
   561	            if let Some(parent) = borrowed.parent_node.as_ref().and_then(Weak::upgrade) {
   562	                println!("  {} -> {} [color=green];", borrowed.key, parent.borrow().key);
   563	            }
   564	            let left = borrowed.left_child_node.clone();
   565	            let right = borrowed.right_child_node.clone();
   566	            drop(borrowed);
   567	
   568	            if let Some(left_node) = left {
   569	                println!("  {} -> {}", node.borrow().key, left_node.borrow().key);
   570	                print_node(&left_node);
   571	            }
   572	            if let Some(right_node) = right {
   573	                println!("  {} -> {}", node.borrow().key, right_node.borrow().key);
   574	                print_node(&right_node);
   575	            }
   576	        }
   577	
   578	        if let Some(root) = self.root_node.as_ref() {
   579	            println!("digraph {{\n  ordering = out;");
   580	            print_node(root);
   581	            println!("}}");
   582	        }
   583	    }
   584	}
   585	/// Increase the weak reference count for a node and return the node.
   586	pub fn bostree_node_weak_ref(node: &Rc<RefCell<BOSNode>>) -> Rc<RefCell<BOSNode>> {
   587	    {
   588	        let mut node_mut = node.borrow_mut();
   589	        assert!(node_mut.weak_ref_count < 127);
   590	        assert!(node_mut.weak_ref_count > 0);
   591	        node_mut.weak_ref_count += 1;
   592	    }
   593	    node.clone()
   594	}
   595	/// Return the next node in an in-order traversal.
   596	pub fn bostree_next_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
   597	    if let Some(mut current) = node.borrow().right_child_node.clone() {
   598	        loop {
   599	            let next = current.borrow().left_child_node.clone();
   600	            if let Some(left) = next {
   601	                current = left;
   602	            } else {
   603	                return Some(current);
   604	            }
   605	        }
   606	    }
   607	
   608	    let mut current = node.clone();
   609	    while let Some(parent) = parent_node(&current) {
   610	        if is_left_child(&parent, &current) {
   611	            return Some(parent);
   612	        }
   613	        current = parent;
   614	    }
   615	    None
   616	}
   617	/// Return the previous node in an in-order traversal.
   618	pub fn bostree_previous_node(node: &Rc<RefCell<BOSNode>>) -> Option<Rc<RefCell<BOSNode>>> {
   619	    if let Some(mut current) = node.borrow().left_child_node.clone() {
   620	        loop {
   621	            let next = current.borrow().right_child_node.clone();
   622	            if let Some(right) = next {
   623	                current = right;
   624	            } else {
   625	                return Some(current);
   626	            }
   627	        }
